    metadata.profileName = "GATEWAY"
    msg = {
        "method": "controlGroup",
        "params": {
            id:metadata.entityName_Room,
            data:dataControl.params
        }
    };

} else {
    if (deviceDirectType.indexOf(msg.profileName) != -1) {
        metadata.profileName = "DEVICE_DIRECT"
        msg = {
            "method": "controlDev",
            "params": {
                bt: dataControl.params.bt,
                dim: dataControl.params.dim
            }
        };

    } else {
        metadata.profileName = msg.profileName
    }
}

