configuration.jsScript:
function extractDeviceNames(devices) {
    var result = [];
    if (!devices || !devices.length) {
        return result;
    }
    for (var i = 0; i < devices.length; i++) {
        if (devices[i] && devices[i].deviceName) {
            result.push(devices[i].deviceName);
        }
    }
    return result;
}

function splitRoomByGateway(input) {
    // =====================================================
    // VALIDATE INPUT
    // =====================================================
    if (
        !input ||
        !input.params ||
        !input.params.devices ||
        !input.params.devices.length
    ) {
        return [];
    }
    var params = input.params;
    var devices = params.devices;
    var groups = params.groups || [];
    var scenes = params.scenes || [];
    // =====================================================
    // gatewayMap
    // =====================================================
    var gatewayMap = {};
    // =====================================================
    // deviceInfoMap
    // deviceName -> detail
    // =====================================================
    var deviceInfoMap = {};
    var i;
    var j;
    // =====================================================
    // STEP 1: Group devices by gateway
    // =====================================================
    for (i = 0; i < devices.length; i++) {
        var device = devices[i];
        if (!device || !device.gateway) {
            continue;
        }
        var gateway = device.gateway;
        if (!gatewayMap[gateway]) {
            gatewayMap[gateway] = {
                devices: [],
                deviceMap: {},
                groups: [],
                groupMap: {},
                scenes: []
            };
        }
        gatewayMap[gateway].devices.push(device);
        gatewayMap[gateway].deviceMap[device.deviceName] = true;
        // =================================================
        // Store device detail
        // =================================================
        deviceInfoMap[device.deviceName] = {
            id: device.deviceName,
            profileName: device.profileName,
            gateway: device.gateway,
            epId: []
        };
    }
    // =====================================================
    // STEP 2: Filter groups for each gateway
    // =====================================================
    for (i = 0; i < groups.length; i++) {
        var group = groups[i];
        for (var gatewayKey in gatewayMap) {
            if (!gatewayMap.hasOwnProperty(gatewayKey)) {
                continue;
            }
            var gatewayData = gatewayMap[gatewayKey];
            var filteredDevices = [];
            var filteredDeviceDetails = [];
            for (j = 0; j < group.devices.length; j++) {
                var deviceName = group.devices[j];
                if (gatewayData.deviceMap[deviceName]) {
                    filteredDevices.push(deviceName);
                    if (deviceInfoMap[deviceName]) {
                        filteredDeviceDetails.push(
                            deviceInfoMap[deviceName]
                        );
                    }
                }
            }
            // =================================================
            // Ignore empty groups
            // =================================================
            if (filteredDevices.length > 0) {
                var newGroup = {
                    id: group.id,
                    name: group.name,
                    type: group.type,
                    // device name array
                    devices: filteredDevices,
                    // detail array
                    deviceDetails: filteredDeviceDetails
                };
                gatewayData.groups.push(newGroup);
                gatewayData.groupMap[group.id] = true;
            }
        }
    }
    // =====================================================
    // STEP 3: Filter scenes by available groups
    // =====================================================
    for (var gatewaySceneKey in gatewayMap) {
        if (!gatewayMap.hasOwnProperty(gatewaySceneKey)) {
            continue;
        }
        var currentGatewayData = gatewayMap[gatewaySceneKey];
        for (i = 0; i < scenes.length; i++) {
            var scene = scenes[i];
            var filteredSceneGroups = [];
            if (!scene.groups || !scene.groups.length) {
                continue;
            }
            for (j = 0; j < scene.groups.length; j++) {
                var sceneGroup = scene.groups[j];
                if (
                    currentGatewayData.groupMap[sceneGroup.id]
                ) {
                    filteredSceneGroups.push(sceneGroup);
                }
            }
            // =================================================
            // Only keep scene if groups still exist
            // =================================================
            if (filteredSceneGroups.length > 0) {
                currentGatewayData.scenes.push({
                    id: scene.id,
                    name: scene.name,
                    image: scene.image,
                    groups: filteredSceneGroups
                });
            }
        }
    }
    // =====================================================
    // STEP 4: Build final output
    // =====================================================
    var result = [];
    for (var gatewayResultKey in gatewayMap) {
        if (!gatewayMap.hasOwnProperty(gatewayResultKey)) {
            continue;
        }
        var item = gatewayMap[gatewayResultKey];
        result.push({
            method: input.method,
            params: {
                id: params.id,
                gateway: gatewayResultKey,
                name: params.name,
                // Convert object[] -> string[]
                devices: extractDeviceNames(item.devices),
                groups: item.groups,
                scenes: item.scenes
            },
            timeout: input.timeout
        });
    }
    return result;
}

msg = splitRoomByGateway(msg);
return { msg: msg, metadata: metadata, msgType: msgType };

