function aggregateBtDim(dataResponse) {
    var result = {
        bt: 0,
        dim: 0
    };

    if (!dataResponse || !dataResponse.length) {
        return result;
    }

    var dimSum = 0;
    var dimCount = 0;

    for (var i = 0; i < dataResponse.length; i++) {
        var item = dataResponse[i];

        if (!item) {
            continue;
        }

        // ===== bt: chỉ cần 1 thằng = 1 là đủ =====
        var bt = parseInt(item.bt, 10);
        if (bt === 1) {
            result.bt = 1;
        }

        // ===== dim: tính trung bình =====
        var dim = parseInt(item.dim, 10);
        if (!isNaN(dim)) {
            dimSum += dim;
            dimCount++;
        }
    }

    if (dimCount > 0) {
        result.dim = Math.round(dimSum / dimCount);
    }

    return result;
}
msg = aggregateBtDim(msg.dataResponse)
return {msg: msg, metadata: metadata, msgType: msgType};

